mapper.update:
UPDATE iot_sensor_data
temperature = #{temperature}, humidity = #{humidity}, pressure = #{pressure}, smoke_density = #{smokeDensity}, dew_point = #{dewPoint}, luminance = #{luminance}, extra_info = #{extraInfo},
WHERE data_id = #{dataId}

mapper.select:
SELECT * FROM iot_sensor_data 
WHERE device_id = #{deviceId} 
AND report_time BETWEEN #{from} AND #{to} 
ORDER BY report_time ASC

SELECT * FROM iot_sensor_data 
WHERE device_id = #{deviceId} 
ORDER BY report_time DESC 
LIMIT #{limit}
